vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Calculate polar coordinates
    vec2 R = vec2(uTexSize.x, uTexSize.y);
    vec2 p = vUvOriginal * R * 2.0 - R;

    // Dynamic rotation speed based on audioLow (cubic easing for stronger response)
    float bassBoost = pow(audioLowSmooth, 3.0); // More aggressive acceleration
    float rotationSpeed = 0.79 * (1.0 + bassBoost/32);

    // Angle calculation with audioLow-accelerated animation
    float angle = atan(p.x, p.y) - uTime * rotationSpeed;

    // Enhanced color wave pattern with audioLow-reactive intensity
    vec4 color = (0.6 + 0.6 * cos(angle + vec4(0, 23, 21, 0)))
